module mux4to1_32bit(  
    input [31:0] data0,  
    input [31:0] data1,  
    input [31:0] data2,  
    input [31:0] data3,  
    input [1:0] select,  
    output reg [31:0] inverted_out  
);  
    always @(*) begin  
        case (select)  
            2'b00: inverted_out = data0;  
            2'b01: inverted_out = data1;  
            2'b10: inverted_out = data2;  
            2'b11: inverted_out = data3;  
            default: inverted_out = 32'b0;  
        endcase  
    end  
endmodule
